{
  "project": "radishflow",
  "task": "suggest_ghost_completion",
  "locale": "zh-CN",
  "answers": [
    {
      "summary": "根据当前选择单元 Flash Drum 511 的未连接端口 vapor_outlet 及就近下游拓扑，提出一条 ghost 连线建议：从 vapor_outlet 创建新物流 VG-511 对接下游蒸汽出口支线。该建议为 tab 默认高置信度候选，且上次跳过冷却已消散，可再次以 Tab 键接受。",
      "issues": [],
      "proposed_actions": [
        {
          "kind": "ghost_completion",
          "title": "补充 Flash Drum 511 蒸汽出口物流 VG-511",
          "target": {
            "unit_id": "flash-32",
            "port_key": "vapor_outlet",
            "description": "Flash Drum 511 的蒸汽出口，当前未连接"
          },
          "rationale": "单元 Flash Drum 511 的 vapor_outlet 端口未连接，就近下游存在 stream_stub（flash-32-vapor-lane），对齐度和拓扑匹配度极高（alignment 0.94, topology 0.93），命名遵循 VG + 单元号 511 的既有模式，无碰撞。上两次已先后完成进料阀及阀到闪蒸罐的 ghost 连线，当前为同一链条的自然延续；该候选在 revision 77 被跳过，但冷却期已过，允许重新作为 tab 默认建议。",
          "patch": {
            "change": "add_stream",
            "stream_name": "VG-511",
            "source_unit_id": "flash-32",
            "source_port": "vapor_outlet",
            "target": {
              "type": "stream_stub",
              "id": "flash-32-vapor-lane"
            },
            "direction": "downstream"
          },
          "preview": {
            "description": "将显示一条从 Flash Drum 511 蒸汽出口引出的虚线物流，标注 VG-511，方向指向下游蒸汽支线。",
            "accept_key": "Tab",
            "manual_only": false,
            "position": {
              "anchor": "vapor_outlet",
              "alignment": "downstream"
            }
          },
          "apply": {
            "command_kind": "accept_ghost_completion",
            "candidate_ref": "cand-flash-32-vapor-outlet",
            "payload": {
              "target_unit_id": "flash-32",
              "target_port_key": "vapor_outlet",
              "stream_name": "VG-511",
              "connect_to_stub_id": "flash-32-vapor-lane"
            }
          },
          "risk_level": "low",
          "requires_confirmation": false
        }
      ],
      "citations": [
        {
          "source": "context.legal_candidate_completions",
          "ref": "cand-flash-32-vapor-outlet",
          "note": "唯一合法候选，高置信度，tab 默认"
        },
        {
          "source": "context.cursor_context.recent_actions",
          "note": "该候选在 revision 77 被跳过，但 topology_pattern_hints 指示冷却期已过，可重新建议"
        },
        {
          "source": "context.naming_hints",
          "note": "前缀 VG 与后缀 511 均来自命名提示，且无碰撞"
        }
      ]
    }
  ],
  "status": "ok"
}
